local FEEDBACK_COOLDOWN, lastFeedback = 20, 0
local ERRMAP = {
    empty = "Le message est vide.", no_links = "Les liens ne sont pas autorisés.",
    too_long = "Le message est trop long (500 caractères maximum).", rate_limited = "Vous avez atteint la limite de 3 messages. Veuillez réessayer plus tard.",
    busy = "Le serveur est occupé. Veuillez réessayer.", banned = "Vous n'êtes pas autorisé à envoyer des commentaires.",
    discord_error = "Échec de l'envoi. Veuillez réessayer.", network = "Erreur réseau.",
    no_request = "Votre exécuteur ne peut pas envoyer de requêtes.", bad_response = "Le serveur a renvoyé une réponse inattendue.",
    unreachable = "Votre exécuteur ne peut pas joindre le serveur (erreur TLS). Veuillez essayer un autre exécuteur.",
}
local FG = Tabs.Suggest:AddLeftGroupbox("Suggestions / Aide", "message-square")
FG:AddDropdown("FeedbackType", {Text = "Type", Values = {"Suggestion", "Bug", "Help"}, Default = "Suggestion", Callback = function() end})
FG:AddInput("FeedbackMsg", {Default = "", Numeric = false, Finished = false, ClearTextOnFocus = false, Text = "Message", Placeholder = "Saisissez votre message (500 caractères maximum, sans liens)"})
local fbStatus = FG:AddLabel("", true)
FG:AddButton({
    Text = "📨 Send",
    Func = function()
        local now = tick()
        if now - lastFeedback < FEEDBACK_COOLDOWN then
            safeSet(fbStatus, string.format("Veuillez attendre %d secondes avant de renvoyer.", math.ceil(FEEDBACK_COOLDOWN - (now - lastFeedback))))
            return
        end
        local ftype = tostring((Options.FeedbackType and Options.FeedbackType.Value) or "Suggestion"):lower()
        local msg   = M.trim((Options.FeedbackMsg and Options.FeedbackMsg.Value) or "")
        if msg == "" then safeSet(fbStatus, "Le message est vide."); return end
        if #msg > 500 then safeSet(fbStatus, "Le message est trop long (500 caractères maximum)."); return end
        local low = msg:lower()
        if low:find("http", 1, true) or low:find("discord.gg", 1, true) or low:find("www.", 1, true) or low:find(".gg/", 1, true) then
            safeSet(fbStatus, "Les liens ne sont pas autorisés."); return
        end
        safeSet(fbStatus, "Envoi...")
        task.spawn(function()
            local sok, err = M.sendFeedback(ftype, msg, (preCheck and preCheck.session_token) or "")
            if sok then
                lastFeedback = tick()
                safeSet(fbStatus, "✅ Envoyé. Merci !")
                pcall(function() Options.FeedbackMsg:SetValue("") end)
                Library:Notify({Title = "COMBOWICK", Description = "Votre commentaire a été envoyé. Merci !", Time = 3})
            else
                safeSet(fbStatus, ERRMAP[err] or ("Échec de l'envoi : " .. tostring(err)))
            end
        end)
    end,
})
FG:AddLabel("3 messages maximum par heure. Aucun lien ni mention.", true)

