task.spawn(function()
    safeSet(statusLabel, "Authentification...")

    local result = M.withRetry(M.checkSession, M.hwid)

    if result == nil then
        safeSet(statusLabel, "Statut : Échec")
        Library:Notify({Title="COMBOWICK", Description="La vérification de la session a échoué.", Time=5})

    elseif result.status == "allowed" or result.status == "session_active" then
        if result.disabled then
            safeSet(statusLabel, "⛔ Jeu désactivé")
            safeSet(hintLabel, "La version gratuite n'est pas disponible ici. Obtenez une clé.")
            Library:Notify({Title="COMBOWICK", Description="La version gratuite est désactivée pour ce jeu. Veuillez utiliser une clé.", Time=6})
            return
        end
        local token = result.session_token
        if type(token) ~= "string" or #token < 20 then
            safeSet(statusLabel, "Statut : Échec")
        else
            safeSet(statusLabel, "Statut : Authentifié")
            Library:Notify({Title="COMBOWICK", Description="Vous êtes authentifié.", Time=3})
            _G.COMBOWICK_FREE   = true
            _G.COMBOWICK_ACTIVE = true
            local remaining = tonumber(result.remaining) or 0
            task.spawn(function()
                while remaining > 0 do
                    local fmt = M.formatTime(remaining)
                    safeSet(timerLabel, string.format("Temps restant : %s", fmt))
                    safeSet(lSession, string.format("Durée de session : %s", fmt))
                    task.wait(1); remaining = remaining - 1
                end
                safeSet(timerLabel, "La session a expiré.")
                safeSet(lSession, "Durée de session : expirée")
                _G.COMBOWICK_ACTIVE = false
                pcall(function() Library:Unload() end)
                task.wait(0.5)
                M.reloadExist()
            end)
            local scriptUrl = M.getScriptForGame(token)
            if M.loadFreeScript(scriptUrl, token) then task.wait(2); pcall(function() Library:Unload() end) end
        end

    elseif result.status == "cooldown" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "En délai d'attente")
        safeSet(hintLabel, "Obtenez une clé de 11 heures, ou attendez la fin du délai d'attente.")
        Library:Notify({Title="COMBOWICK", Description="Vous êtes en délai d'attente. Obtenez une clé pour éviter l'attente.", Time=6})
        task.spawn(function()
            while remaining > 0 do
                local fmt = M.formatTime(remaining)
                safeSet(timerLabel, string.format("Délai d'attente : %s", fmt))
                safeSet(lCooldown, string.format("Délai d'attente : %s", fmt))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Le délai d'attente est terminé.")
            safeSet(lCooldown, "Délai d'attente : terminé")
            safeSet(hintLabel, "")
            Library:Notify({Title="COMBOWICK", Description="Le délai d'attente est terminé. Rechargement...", Time=3})
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "throttled" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "Trop de requêtes")
        safeSet(hintLabel, "Trop de requêtes. Veuillez patienter.")
        Library:Notify({Title="COMBOWICK", Description="Trop de requêtes. Veuillez patienter un instant.", Time=5})
        task.spawn(function()
            while remaining > 0 do
                safeSet(timerLabel, string.format("Réessai dans %s", M.formatTime(remaining)))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Rechargement...")
            safeSet(hintLabel, "")
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "disabled" then
        safeSet(statusLabel, "Service suspendu")
        safeSet(hintLabel, "COMBOWICK est temporairement hors ligne.")
        Library:Notify({Title="COMBOWICK", Description="Le service est actuellement désactivé. Veuillez réessayer plus tard.", Time=6})

    elseif result.status == "banned" then
        safeSet(statusLabel, "Banni")
        Library:Notify({Title="COMBOWICK", Description="Vous êtes banni.", Time=5})

    elseif result.status == "game_not_allowed" then
        safeSet(statusLabel, "🚫 Jeu non pris en charge")
        safeSet(hintLabel, "Ce jeu n'est pas encore pris en charge. Les clés premium fonctionnent toujours si un script est disponible.")
        Library:Notify({Title="COMBOWICK", Description="Ce jeu n'est pas encore pris en charge.", Time=6})

    else
        safeSet(statusLabel, "Erreur")
        safeSet(hintLabel, "Impossible de joindre le serveur. Veuillez relancer le script.")
        Library:Notify({Title="COMBOWICK", Description=tostring(result.message or "Une erreur inconnue s'est produite."), Time=5})
    end
end)

